#include "interface.h"

#include <vector>

uint64_t packed12_filter_sum(const std::vector<uint8_t>& packed, uint16_t threshold, int iters) {
    const std::size_t max_i = (packed.size() / 3u) * 3u;
    const uint32_t thr = static_cast<uint32_t>(threshold);
    uint64_t sum = 0;

    for (int iter = 0; iter < iters; ++iter) {
        sum = 0;
        for (std::size_t i = 0; i < max_i; i += 3u) {
            const uint32_t a =
                static_cast<uint32_t>(packed[i]) |
                (static_cast<uint32_t>(packed[i + 1u] & 0x0fu) << 8u);
            const uint32_t b =
                (static_cast<uint32_t>(packed[i + 1u] >> 4u)) |
                (static_cast<uint32_t>(packed[i + 2u]) << 4u);

            if (a > thr) sum += a;
            if (b > thr) sum += b;
        }
    }
    return sum;
}
